"use server";

import { revalidatePath } from "next/cache";
import { createClient } from "@/lib/supabase/server";
import { registerCarpoolSchema } from "@/lib/validations/carpool";
import { ActionResult } from "@/types/action";

// 카풀 등록
export async function registerCarpool(formData: FormData): Promise<ActionResult> {
  const supabase = await createClient();
  const { data: { user }, error: authError } = await supabase.auth.getUser();

  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다." };
  }

  const rawData = {
    eventId: formData.get("eventId") as string,
    departurePlace: formData.get("departurePlace") as string,
    departureTime: formData.get("departureTime") as string | undefined,
    totalSeats: parseInt(formData.get("totalSeats") as string, 10),
    description: formData.get("description") as string | undefined,
  };

  const validated = registerCarpoolSchema.safeParse(rawData);
  if (!validated.success) {
    return { success: false, error: validated.error.issues[0].message };
  }

  const { eventId, departurePlace, departureTime, totalSeats, description } = validated.data;

  // 권한 확인: 주최자 또는 승인된 참여자
  const { data: participation } = await supabase
    .from("participations")
    .select("status")
    .eq("event_id", eventId)
    .eq("user_id", user.id)
    .single();

  const { data: event } = await supabase
    .from("events")
    .select("host_id")
    .eq("id", eventId)
    .single();

  const isHost = event?.host_id === user.id;
  const isApproved = participation?.status === "approved";

  if (!isHost && !isApproved) {
    return { success: false, error: "카풀을 등록할 권한이 없습니다." };
  }

  const { error } = await supabase.from("carpools").insert({
    event_id: eventId,
    driver_id: user.id,
    departure_place: departurePlace,
    departure_time: departureTime || null,
    total_seats: totalSeats,
    description: description || null,
  });

  if (error) {
    return { success: false, error: error.message };
  }

  revalidatePath(`/events/${eventId}`);
  return { success: true };
}

// 카풀 삭제
export async function deleteCarpool(
  carpoolId: string,
  eventId: string,
): Promise<ActionResult> {
  const supabase = await createClient();
  const { data: { user }, error: authError } = await supabase.auth.getUser();

  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다." };
  }

  // 권한 확인: 드라이버 또는 주최자
  const { data: carpool } = await supabase
    .from("carpools")
    .select("driver_id")
    .eq("id", carpoolId)
    .single();

  const { data: event } = await supabase
    .from("events")
    .select("host_id")
    .eq("id", eventId)
    .single();

  if (!carpool || !event) {
    return { success: false, error: "카풀을 찾을 수 없습니다." };
  }

  if (carpool.driver_id !== user.id && event.host_id !== user.id) {
    return { success: false, error: "권한이 없습니다." };
  }

  const { error } = await supabase.from("carpools").delete().eq("id", carpoolId);

  if (error) {
    return { success: false, error: error.message };
  }

  revalidatePath(`/events/${eventId}`);
  return { success: true };
}
